1	type Item = { type: string; material?: string; enchantment?: number; cursed?: boolean };
2	type QuoteStep = { op: "quote"; items: Item[] };
3	type Damage = { itemType: string; amount: number };
4	type Incident = { cause: string; damages: Damage[] };
5	type ClaimStep = { op: "claim"; policy: number; incident: Incident };
6	type Step = QuoteStep | ClaimStep;
7	type Customer = { yearsWithMHPCO: number };
8	type Scenario = { customer: Customer; steps: Step[] };
9	
10	type QuoteResult = { premium: number };
11	type ClaimResult = { payout: number; remainingCap: number };
12	type StepResult = QuoteResult | ClaimResult;
13	
14	const PROCESSING_FEE = 5;
15	const FIRST_INSURANCE_SURCHARGE = 0.1;
16	const LOYALTY_DISCOUNT = 0.2;
17	const LOYALTY_YEARS_THRESHOLD = 2;
18	const FOLLOWUP_CONTRACT_DISCOUNT = 0.15;
19	const CURSE_SURCHARGE = 0.5;
20	const HIGH_ENCHANTMENT_SURCHARGE = 0.3;
21	const HIGH_ENCHANTMENT_THRESHOLD = 5;
22	const COMPONENT_BLOCK_SIZE = 3;
23	const COMPONENT_BLOCK_PRICE = 60;
24	
25	const BASE_PREMIUM_BY_TYPE: Record<string, number> = {
26	  sword: 100,
27	  amulet: 60,
28	  staff: 80,
29	  potion: 40,
30	  rune: 25,
31	  moonstone: 25,
32	};
33	
34	const INSURANCE_VALUE_BY_TYPE: Record<string, number> = {
35	  sword: 1000,
36	  amulet: 600,
37	  staff: 800,
38	  potion: 400,
39	  rune: 250,
40	  moonstone: 250,
41	};
42	
43	const DEDUCTIBLE_PER_DAMAGE = 100;
44	const CAP_MULTIPLIER = 2;
45	
46	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
47	
48	const basePremiumOf = (item: Item): number => BASE_PREMIUM_BY_TYPE[item.type];
49	
50	const isComponent = (item: Item): boolean => COMPONENT_TYPES.has(item.type);
51	
52	const priceForComponentGroup = (type: string, count: number): number =>
53	  count === COMPONENT_BLOCK_SIZE
54	    ? COMPONENT_BLOCK_PRICE
55	    : count * BASE_PREMIUM_BY_TYPE[type];
56	
57	const countByType = (items: Item[]): Map<string, number> => {
58	  const counts = new Map<string, number>();
59	  for (const item of items) {
60	    counts.set(item.type, (counts.get(item.type) ?? 0) + 1);
61	  }
62	  return counts;
63	};
64	
65	const sumBasePremiumsFor = (items: Item[]): number => {
66	  const mainItemsTotal = items
67	    .filter((item) => !isComponent(item))
68	    .reduce((sum, item) => sum + basePremiumOf(item), 0);
69	
70	  const componentsTotal = Array.from(countByType(items.filter(isComponent)))
71	    .reduce((sum, [type, count]) => sum + priceForComponentGroup(type, count), 0);
72	
73	  return mainItemsTotal + componentsTotal;
74	};
75	
76	// Item surcharges: each rule adds a percentage of the item's base premium when it applies.
77	const ITEM_SURCHARGE_RULES: { applies: (item: Item) => boolean; rate: number }[] = [
78	  { applies: (item) => item.cursed === true, rate: CURSE_SURCHARGE },
79	  { applies: (item) => (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD, rate: HIGH_ENCHANTMENT_SURCHARGE },
80	];
81	
82	const surchargeRateFor = (item: Item): number =>
83	  ITEM_SURCHARGE_RULES.reduce((rate, rule) => rate + (rule.applies(item) ? rule.rate : 0), 0);
84	
85	const itemSurchargesFor = (items: Item[]): number =>
86	  items.reduce((sum, item) => sum + basePremiumOf(item) * surchargeRateFor(item), 0);
87	
88	type PolicyContext = { customer: Customer; quoteIndex: number };
89	
90	// Policy modifiers: each rule applies a +/- percentage of the policy base when its predicate holds.
91	const POLICY_MODIFIER_RULES: { applies: (ctx: PolicyContext) => boolean; rate: number }[] = [
92	  { applies: () => true, rate: FIRST_INSURANCE_SURCHARGE },
93	  { applies: (ctx) => ctx.customer.yearsWithMHPCO >= LOYALTY_YEARS_THRESHOLD, rate: -LOYALTY_DISCOUNT },
94	  { applies: (ctx) => ctx.quoteIndex > 0, rate: -FOLLOWUP_CONTRACT_DISCOUNT },
95	];
96	
97	const policyModifierRateFor = (ctx: PolicyContext): number =>
98	  POLICY_MODIFIER_RULES.reduce((rate, rule) => rate + (rule.applies(ctx) ? rule.rate : 0), 0);
99	
100	const computePremium = (items: Item[], ctx: PolicyContext): number => {
101	  const policyBase = sumBasePremiumsFor(items);
102	  const itemSurcharges = itemSurchargesFor(items);
103	  const policyModifiers = policyBase * policyModifierRateFor(ctx);
104	  return policyBase + itemSurcharges + policyModifiers + PROCESSING_FEE;
105	};
106	
107	// Rounds up to the nearest whole gold piece, in MHPCO's favor.
108	// Cleans float noise (e.g. 66.00000000000001) before ceiling.
109	const roundUpToGold = (amount: number): number =>
110	  Math.ceil(Math.round(amount * 1e6) / 1e6);
111	
112	type Policy = { items: Item[]; cap: number; remainingCap: number };
113	
114	const insuranceSumFor = (items: Item[]): number =>
115	  items.reduce((sum, item) => sum + INSURANCE_VALUE_BY_TYPE[item.type], 0);
116	
117	const roundDownToGold = (amount: number): number =>
118	  Math.floor(Math.round(amount * 1e6) / 1e6);
119	
120	const payoutForDamage = (damage: Damage): number =>
121	  Math.max(0, damage.amount - DEDUCTIBLE_PER_DAMAGE);
122	
123	const processClaim = (step: ClaimStep, policies: Policy[]): ClaimResult => {
124	  const policy = policies[step.policy];
125	  const grossPayout = step.incident.damages.reduce((sum, d) => sum + payoutForDamage(d), 0);
126	  const cappedPayout = Math.min(grossPayout, policy.remainingCap);
127	  const payout = roundDownToGold(cappedPayout);
128	  policy.remainingCap -= payout;
129	  return { payout, remainingCap: policy.remainingCap };
130	};
131	
132	export const runScenario = (scenario: Scenario): { results: StepResult[] } => {
133	  const policies: Policy[] = [];
134	  let quoteIndex = 0;
135	  const results: StepResult[] = scenario.steps.map((step) => {
136	    if (step.op === "quote") {
137	      const ctx: PolicyContext = { customer: scenario.customer, quoteIndex };
138	      quoteIndex += 1;
139	      const insuranceSum = insuranceSumFor(step.items);
140	      const cap = insuranceSum * CAP_MULTIPLIER;
141	      policies.push({ items: step.items, cap, remainingCap: cap });
142	      return { premium: roundUpToGold(computePremium(step.items, ctx)) };
143	    }
144	    return processClaim(step, policies);
145	  });
146	  return { results };
147	};
