112	type Policy = { items: Item[]; cap: number; remainingCap: number };
113	
114	const insuranceSumFor = (items: Item[]): number =>
115	  items.reduce((sum, item) => sum + INSURANCE_VALUE_BY_TYPE[item.type], 0);
116	
117	const roundDownToGold = (amount: number): number =>
118	  Math.floor(Math.round(amount * 1e6) / 1e6);
119	
120	const payoutForDamage = (damage: Damage): number =>
121	  Math.max(0, damage.amount - DEDUCTIBLE_PER_DAMAGE);
122	
123	const grossPayoutFor = (incident: Incident): number =>
124	  incident.damages.reduce((sum, d) => sum + payoutForDamage(d), 0);
