128	const applyQuote = (
129	  state: ScenarioState,
130	  step: QuoteStep,
131	  customer: Customer,
132	): ScenarioState => {
133	  const ctx: PolicyContext = { customer, quoteIndex: state.policies.length };
134	  const cap = insuranceSumFor(step.items) * CAP_MULTIPLIER;
135	  const policy: Policy = { items: step.items, cap, remainingCap: cap };
136	  const result: QuoteResult = { premium: roundUpToGold(computePremium(step.items, ctx)) };
137	  return {
138	    policies: [...state.policies, policy],
