143	const applyClaim = (state: ScenarioState, step: ClaimStep): ScenarioState => {
144	  const policy = state.policies[step.policy];
145	  const payout = roundDownToGold(Math.min(grossPayoutFor(step.incident), policy.remainingCap));
146	  const updatedPolicy: Policy = { ...policy, remainingCap: policy.remainingCap - payout };
147	  return {
148	    policies: state.policies.map((p, i) => (i === step.policy ? updatedPolicy : p)),
149	    results: [...state.results, { payout, remainingCap: updatedPolicy.remainingCap }],
150	  };
151	};
